# ai_sprint_metrics.py — track AI-specific sprint health signals

from dataclasses import dataclass, field
from typing import List, Optional
from datetime import date

@dataclass
class ResearchSpike:
    title: str
    hypothesis: str
    time_boxed_days: int
    actual_days_spent: Optional[int] = None
    outcome: Optional[str] = None  # "proceed" | "defer" | "abandon"
    decision_document_url: Optional[str] = None

    @property
    def is_complete(self) -> bool:
        return self.outcome is not None

@dataclass
class ModelMetricSnapshot:
    metric_name: str
    value: float
    target: float
    sprint_number: int
    date: date

    @property
    def pct_of_target(self) -> float:
        return (self.value / self.target * 100) if self.target else 0

@dataclass
class SprintHealthRecord:
    sprint_number: int
    start_date: date
    end_date: date
    committed_points: int
    completed_points: int
    research_spikes: List[ResearchSpike] = field(default_factory=list)
    model_metrics: List[ModelMetricSnapshot] = field(default_factory=list)

    @property
    def velocity(self) -> float:
        return (self.completed_points / self.committed_points * 100) if self.committed_points else 0

    @property
    def spikes_completed(self) -> int:
        return sum(1 for s in self.research_spikes if s.is_complete)

    def sprint_review_summary(self) -> dict:
        model_health = {}
        for m in self.model_metrics:
            model_health[m.metric_name] = {
                "value": round(m.value, 3),
                "target": round(m.target, 3),
                "pct_of_target": round(m.pct_of_target, 1),
                "status": "green" if m.pct_of_target >= 95 else ("amber" if m.pct_of_target >= 85 else "red"),
            }
        return {
            "sprint": self.sprint_number,
            "velocity_pct": round(self.velocity, 1),
            "spikes_completed": f"{self.spikes_completed}/{len(self.research_spikes)}",
            "model_health": model_health,
        }
